mapper.select:
select pm.*, ptc.id trainingCampId, ptc.name trainingCampName from pf_member pm left join pf_training_camp ptc on pm.training_camp_id = ptc.id
pm.name like concat('%', #{name}, '%')
and pm.membership_level = #{membershipLevel}
and pm.training_camp_id = #{trainingCampId}
order by pm.update_time desc
